{
  "name": "Xueqiu Tracker AI",
  "description": "A portfolio tracking dashboard that calculates daily changes (adds/removes) in stock lists and uses Gemini to analyze the investment strategy shifts. Supports historical timelines and local data persistence."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Stock {
  symbol: string;
  name: string;
  price?: number;
  changePercent?: number;
  sector?: string; // Optional, for AI to infer
}

export interface PortfolioSnapshot {
  id: string;
  date: string; // ISO Date string
  timestamp: number;
  stocks: Stock[];
  notes?: string;
}

export interface PortfolioChange {
  date: string;
  added: Stock[];
  removed: Stock[];
  retained: Stock[];
  aiAnalysis?: string;
}

export enum ViewMode {
  DASHBOARD = 'DASHBOARD',
  HISTORY = 'HISTORY',
  IMPORT = 'IMPORT'
}

export interface AIAnalysisResult {
  analysis: string;
  sentiment: 'Bullish' | 'Bearish' | 'Neutral' | 'Defensive';
}

import { PortfolioSnapshot, Stock } from '../types';

const STORAGE_KEY = 'xueqiu_tracker_snapshots';

export const getSnapshots = (): PortfolioSnapshot[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  } catch (error) {
    console.error("Failed to load snapshots", error);
    return [];
  }
};

export const saveSnapshot = (snapshot: PortfolioSnapshot): PortfolioSnapshot[] => {
  const current = getSnapshots();
  // Avoid duplicates for same day if needed, or just append
  const updated = [...current, snapshot].sort((a, b) => b.timestamp - a.timestamp);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
  return updated;
};

export const clearHistory = () => {
  localStorage.removeItem(STORAGE_KEY);
};

// Helper to generate a unique ID
export const generateId = () => Math.random().toString(36).substr(2, 9);

// Demo Data Generator
export const generateDemoData = (): PortfolioSnapshot[] => {
  const today = new Date();
  const yesterday = new Date(today);
  yesterday.setDate(yesterday.getDate() - 1);
  const lastWeek = new Date(today);
  lastWeek.setDate(lastWeek.getDate() - 7);

  const baseStocks: Stock[] = [
    { symbol: 'SH600519', name: '贵州茅台', price: 1700.50, changePercent: 1.2 },
    { symbol: 'SZ000858', name: '五粮液', price: 150.20, changePercent: -0.5 },
    { symbol: 'SH601318', name: '中国平安', price: 45.30, changePercent: 0.1 },
    { symbol: 'SZ300750', name: '宁德时代', price: 210.00, changePercent: 2.5 },
  ];

  const snapshots: PortfolioSnapshot[] = [
    {
      id: 'snap-1',
      date: lastWeek.toISOString(),
      timestamp: lastWeek.getTime(),
      stocks: baseStocks,
      notes: 'Initial tracking start'
    },
    {
      id: 'snap-2',
      date: yesterday.toISOString(),
      timestamp: yesterday.getTime(),
      stocks: [
        ...baseStocks.filter(s => s.symbol !== 'SH601318'), // Removed Ping An
        { symbol: 'SH600036', name: '招商银行', price: 32.10, changePercent: 0.8 }, // Added CMB
        { symbol: 'SZ002594', name: '比亚迪', price: 250.50, changePercent: 1.5 } // Added BYD
      ],
      notes: 'Shift towards EV sector'
    },
    {
      id: 'snap-3',
      date: today.toISOString(),
      timestamp: today.getTime(),
      stocks: [
        ...baseStocks.filter(s => s.symbol !== 'SH601318'),
        { symbol: 'SH600036', name: '招商银行', price: 32.50, changePercent: 1.2 },
        { symbol: 'SZ002594', name: '比亚迪', price: 255.00, changePercent: 1.8 },
        { symbol: 'SH688981', name: '中芯国际', price: 55.00, changePercent: 5.2 } // Added SMIC
      ],
      notes: 'Adding Tech exposure'
    }
  ];

  localStorage.setItem(STORAGE_KEY, JSON.stringify(snapshots.reverse()));
  return snapshots.reverse(); // Newest first
};

import { GoogleGenAI, Type } from "@google/genai";
import { PortfolioChange, AIAnalysisResult } from "../types";

// Safety check for API Key
const apiKey = process.env.API_KEY || '';

const ai = new GoogleGenAI({ apiKey });

export const analyzePortfolioChange = async (change: PortfolioChange): Promise<AIAnalysisResult> => {
  if (!apiKey) {
    return {
      analysis: "API Key is missing. Cannot perform AI analysis.",
      sentiment: "Neutral"
    };
  }

  const addedNames = change.added.map(s => `${s.name} (${s.symbol})`).join(', ');
  const removedNames = change.removed.map(s => `${s.name} (${s.symbol})`).join(', ');

  if (change.added.length === 0 && change.removed.length === 0) {
    return {
      analysis: "No changes detected in the portfolio today. The investor is holding their position.",
      sentiment: "Neutral"
    };
  }

  const prompt = `
    You are a professional financial analyst tracking a high-profile investor's portfolio (Smart Money).

    The investor made the following changes on ${new Date(change.date).toLocaleDateString()}:

    ADDED STOCKS: ${addedNames || 'None'}
    REMOVED STOCKS: ${removedNames || 'None'}

    Please provide a concise analysis (max 100 words) of what this shift might imply about their strategy. 
    Are they moving to defensive sectors? Taking profits? Betting on tech?

    Also classify the sentiment of this move as: Bullish, Bearish, Neutral, or Defensive.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            analysis: { type: Type.STRING },
            sentiment: { type: Type.STRING, enum: ['Bullish', 'Bearish', 'Neutral', 'Defensive'] }
          },
          required: ['analysis', 'sentiment']
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("Empty response from AI");

    return JSON.parse(text) as AIAnalysisResult;

  } catch (error) {
    console.error("Gemini Analysis Failed:", error);
    return {
      analysis: "Failed to analyze portfolio changes due to an API error.",
      sentiment: "Neutral"
    };
  }
};

import React from 'react';
import { Stock } from '../types';

interface StockCardProps {
  stock: Stock;
  status?: 'added' | 'removed' | 'neutral';
}

export const StockCard: React.FC<StockCardProps> = ({ stock, status = 'neutral' }) => {
  const isPositive = (stock.changePercent || 0) >= 0;

  let borderColor = "border-gray-200";
  let badgeColor = "bg-gray-100 text-gray-600";
  let badgeText = "";

  if (status === 'added') {
    borderColor = "border-green-200 bg-green-50/50";
    badgeColor = "bg-green-100 text-green-700";
    badgeText = "NEW";
  } else if (status === 'removed') {
    borderColor = "border-red-200 bg-red-50/50";
    badgeColor = "bg-red-100 text-red-700";
    badgeText = "SOLD";
  }

  return (
    <div className={`relative p-4 rounded-xl border ${borderColor} shadow-sm transition-all hover:shadow-md bg-white`}>
      <div className="flex justify-between items-start mb-2">
        <div>
          <h3 className="font-bold text-gray-900">{stock.name}</h3>
          <p className="text-xs text-gray-500 font-mono">{stock.symbol}</p>
        </div>
        {status !== 'neutral' && (
          <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${badgeColor}`}>
            {badgeText}
          </span>
        )}
      </div>

      <div className="flex justify-between items-end mt-2">
        <span className="text-lg font-semibold text-gray-800">
          {stock.price ? `¥${stock.price.toFixed(2)}` : '--'}
        </span>
        {stock.changePercent !== undefined && (
          <span className={`text-sm font-medium ${isPositive ? 'text-red-500' : 'text-green-500'}`}>
            {isPositive ? '+' : ''}{stock.changePercent}%
          </span>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { PortfolioSnapshot, PortfolioChange } from '../types';
import { StockCard } from './StockCard';
import { analyzePortfolioChange } from '../services/geminiService';

interface HistoryTimelineProps {
  snapshots: PortfolioSnapshot[];
}

export const HistoryTimeline: React.FC<HistoryTimelineProps> = ({ snapshots }) => {
  const [analyzingIds, setAnalyzingIds] = useState<Set<string>>(new Set());
  const [analyses, setAnalyses] = useState<Record<string, { text: string; sentiment: string }>>({});

  // Compute diffs
  const changes: PortfolioChange[] = [];

  // Snapshots are expected to be Newest First
  for (let i = 0; i < snapshots.length - 1; i++) {
    const current = snapshots[i];
    const previous = snapshots[i + 1]; // Older

    const currentSymbols = new Set(current.stocks.map(s => s.symbol));
    const previousSymbols = new Set(previous.stocks.map(s => s.symbol));

    const added = current.stocks.filter(s => !previousSymbols.has(s.symbol));
    const removed = previous.stocks.filter(s => !currentSymbols.has(s.symbol));
    const retained = current.stocks.filter(s => previousSymbols.has(s.symbol));

    changes.push({
      date: current.date,
      added,
      removed,
      retained
    });
  }

  const handleAnalyze = async (change: PortfolioChange, idx: number) => {
    const changeId = `${change.date}-${idx}`;
    if (analyzingIds.has(changeId)) return;

    setAnalyzingIds(prev => new Set(prev).add(changeId));

    const result = await analyzePortfolioChange(change);

    setAnalyses(prev => ({
      ...prev,
      [changeId]: { text: result.analysis, sentiment: result.sentiment }
    }));

    setAnalyzingIds(prev => {
      const newSet = new Set(prev);
      newSet.delete(changeId);
      return newSet;
    });
  };

  if (snapshots.length < 2) {
    return (
      <div className="text-center py-12 bg-white rounded-xl border border-dashed border-gray-300">
        <p className="text-gray-500">Need at least 2 snapshots to track changes.</p>
        <p className="text-sm text-gray-400 mt-2">Import more data or generate demo history.</p>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      {changes.map((change, idx) => {
        const changeId = `${change.date}-${idx}`;
        const hasAnalysis = !!analyses[changeId];
        const isAnalyzing = analyzingIds.has(changeId);
        const sentiment = analyses[changeId]?.sentiment;

        let sentimentColor = 'bg-gray-100 text-gray-600';
        if (sentiment === 'Bullish') sentimentColor = 'bg-red-100 text-red-700'; // Red is up in China
        if (sentiment === 'Bearish') sentimentColor = 'bg-green-100 text-green-700';
        if (sentiment === 'Defensive') sentimentColor = 'bg-blue-100 text-blue-700';

        return (
          <div key={changeId} className="relative pl-8 pb-8 border-l-2 border-gray-200 last:border-0 last:pb-0">
            {/* Timeline Dot */}
            <div className="absolute -left-[9px] top-0 w-4 h-4 rounded-full bg-blue-500 border-4 border-white shadow-sm" />

            <div className="mb-4 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
              <div>
                <h3 className="text-lg font-bold text-gray-900">
                  {new Date(change.date).toLocaleDateString(undefined, { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
                </h3>
                <p className="text-sm text-gray-500">
                  {change.added.length} Added · {change.removed.length} Removed
                </p>
              </div>

              {!hasAnalysis && (change.added.length > 0 || change.removed.length > 0) && (
                 <button
                 onClick={() => handleAnalyze(change, idx)}
                 disabled={isAnalyzing}
                 className="flex items-center space-x-2 px-4 py-2 bg-gradient-to-r from-violet-600 to-indigo-600 text-white text-sm font-medium rounded-lg shadow-sm hover:shadow-md disabled:opacity-50 transition-all"
               >
                 {isAnalyzing ? (
                   <>
                     <svg className="animate-spin h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                       <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                       <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                     </svg>
                     <span>Analyst Thinking...</span>
                   </>
                 ) : (
                   <>
                     <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                     <span>Ask AI Analyst</span>
                   </>
                 )}
               </button>
              )}
            </div>

            {/* AI Analysis Box */}
            {hasAnalysis && (
              <div className="mb-6 p-4 bg-gradient-to-br from-indigo-50 to-violet-50 rounded-xl border border-indigo-100">
                <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center space-x-2">
                    <svg className="w-5 h-5 text-indigo-600" fill="currentColor" viewBox="0 0 20 20"><path d="M13 6a3 3 0 11-6 0 3 3 0 016 0zM18 8a2 2 0 11-4 0 2 2 0 014 0zM14 15a4 4 0 00-8 0v3h8v-3zM6 8a2 2 0 11-4 0 2 2 0 014 0zM16 18v-3a5.972 5.972 0 00-.75-2.906A3.005 3.005 0 0119 15v3h-3zM4.75 12.094A5.973 5.973 0 004 15v3H1v-3a3 3 0 013.75-2.906z" /></svg>
                    <span className="font-semibold text-indigo-900">AI Strategy Insight</span>
                  </div>
                  <span className={`px-2 py-1 rounded text-xs font-bold uppercase ${sentimentColor}`}>
                    {analyses[changeId].sentiment}
                  </span>
                </div>
                <p className="text-sm text-indigo-800 leading-relaxed">
                  {analyses[changeId].text}
                </p>
              </div>
            )}

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              {change.added.length > 0 && (
                <div className="bg-green-50/30 rounded-lg p-4 border border-green-100">
                  <h4 className="text-xs font-bold text-green-700 uppercase tracking-wider mb-3 flex items-center">
                    <span className="w-2 h-2 rounded-full bg-green-500 mr-2"></span>
                    Opened Positions
                  </h4>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    {change.added.map(stock => (
                      <StockCard key={stock.symbol} stock={stock} status="added" />
                    ))}
                  </div>
                </div>
              )}

              {change.removed.length > 0 && (
                <div className="bg-red-50/30 rounded-lg p-4 border border-red-100">
                  <h4 className="text-xs font-bold text-red-700 uppercase tracking-wider mb-3 flex items-center">
                    <span className="w-2 h-2 rounded-full bg-red-500 mr-2"></span>
                    Closed Positions
                  </h4>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    {change.removed.map(stock => (
                      <StockCard key={stock.symbol} stock={stock} status="removed" />
                    ))}
                  </div>
                </div>
              )}
            </div>

            {change.added.length === 0 && change.removed.length === 0 && (
               <div className="text-sm text-gray-400 italic">No changes made to the portfolio on this day.</div>
            )}
          </div>
        );
      })}
    </div>
  );
};

import React, { useState } from 'react';
import { Stock, PortfolioSnapshot } from '../types';
import { generateId } from '../services/storageService';

interface ImporterProps {
  onImport: (snapshot: PortfolioSnapshot) => void;
  onGenerateDemo: () => void;
}

export const Importer: React.FC<ImporterProps> = ({ onImport, onGenerateDemo }) => {
  const [textInput, setTextInput] = useState('');
  const [error, setError] = useState('');

  const handleParse = () => {
    try {
      setError('');
      // Attempt to parse various formats. 
      // User might paste a simple list of names or a JSON.
      // For this demo, we assume a JSON array of objects or simple list.

      let stocks: Stock[] = [];
      const trimmed = textInput.trim();

      if (trimmed.startsWith('[')) {
        // Assume JSON
        const parsed = JSON.parse(trimmed);
        if (Array.isArray(parsed)) {
          stocks = parsed.map((item: any) => ({
            symbol: item.symbol || item.code || 'UNKNOWN',
            name: item.name || item.stockName || 'Unknown Stock',
            price: Number(item.price || item.current || 0),
            changePercent: Number(item.percent || item.change || 0)
          }));
        }
      } else {
        // Assume line separated "Name Symbol" or just "Name"
        const lines = trimmed.split('\n');
        stocks = lines.map(line => {
           const parts = line.split(/[\s\t,]+/);
           return {
             name: parts[0] || 'Unknown',
             symbol: parts[1] || `SYM-${Math.floor(Math.random()*1000)}`,
             price: 0,
             changePercent: 0
           };
        }).filter(s => s.name.length > 0);
      }

      if (stocks.length === 0) {
        throw new Error("No valid stocks found in input");
      }

      const snapshot: PortfolioSnapshot = {
        id: generateId(),
        date: new Date().toISOString(),
        timestamp: Date.now(),
        stocks
      };

      onImport(snapshot);
      setTextInput('');
    } catch (e) {
      setError("Failed to parse input. Please ensure it's a JSON array of stocks or line-separated list.");
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 max-w-2xl mx-auto">
      <div className="text-center mb-6">
        <h2 className="text-xl font-bold text-gray-900">Update Portfolio Data</h2>
        <p className="text-gray-500 text-sm mt-1">
          Paste the stock list JSON from Xueqiu or enter manual data.
        </p>
      </div>

      <div className="mb-4">
        <textarea
          className="w-full h-48 p-4 bg-gray-50 border border-gray-200 rounded-lg text-sm font-mono focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
          placeholder={`Example JSON format:
[
  { "name": "Moutai", "symbol": "SH600519", "price": 1700, "percent": 1.2 },
  { "name": "Tencent", "symbol": "HK00700", "price": 300, "percent": -0.5 }
]`}
          value={textInput}
          onChange={(e) => setTextInput(e.target.value)}
        />
        {error && <p className="text-red-500 text-xs mt-2">{error}</p>}
      </div>

      <div className="flex flex-col sm:flex-row gap-3">
        <button
          onClick={handleParse}
          disabled={!textInput}
          className="flex-1 bg-blue-600 hover:bg-blue-700 text-white font-semibold py-2 px-4 rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
        >
          Import Data
        </button>
        <button
          onClick={onGenerateDemo}
          className="flex-1 bg-white border border-gray-300 text-gray-700 hover:bg-gray-50 font-semibold py-2 px-4 rounded-lg transition-colors"
        >
          Load Demo History (sth_)
        </button>
      </div>

      <div className="mt-6 p-4 bg-yellow-50 rounded-lg border border-yellow-100">
        <h4 className="text-xs font-bold text-yellow-800 uppercase mb-2">Note on Scraping</h4>
        <p className="text-xs text-yellow-700 leading-relaxed">
          Due to browser security policies (CORS) and Xueqiu's login requirement, this web app cannot automatically fetch data from <code>xueqiu.com</code>. 
          Please manually copy the JSON response from your browser's Network tab or use a browser extension to copy the data, then paste it here to track changes.
        </p>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { ViewMode, PortfolioSnapshot, Stock } from './types';
import { getSnapshots, saveSnapshot, clearHistory, generateDemoData } from './services/storageService';
import { HistoryTimeline } from './components/HistoryTimeline';
import { Importer } from './components/Importer';
import { StockCard } from './components/StockCard';

function App() {
  const [snapshots, setSnapshots] = useState<PortfolioSnapshot[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>(ViewMode.DASHBOARD);

  useEffect(() => {
    // Load initial data
    const loaded = getSnapshots();
    setSnapshots(loaded);
  }, []);

  const handleImport = (newSnapshot: PortfolioSnapshot) => {
    const updated = saveSnapshot(newSnapshot);
    setSnapshots(updated);
    setViewMode(ViewMode.DASHBOARD);
  };

  const handleGenerateDemo = () => {
    const demo = generateDemoData();
    setSnapshots(demo);
    setViewMode(ViewMode.DASHBOARD);
  };

  const handleClear = () => {
    if (confirm("Are you sure you want to delete all history?")) {
      clearHistory();
      setSnapshots([]);
    }
  };

  // Derived state
  const latestSnapshot = snapshots.length > 0 ? snapshots[0] : null;
  const currentStocks = latestSnapshot ? latestSnapshot.stocks : [];

  return (
    <div className="min-h-screen font-sans text-slate-800">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <div className="flex items-center gap-3">
              <div className="bg-blue-600 p-2 rounded-lg">
                <svg className="w-5 h-5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" />
                </svg>
              </div>
              <h1 className="text-xl font-bold tracking-tight text-gray-900">
                Xueqiu Tracker <span className="text-blue-600">AI</span>
              </h1>
            </div>

            <nav className="flex items-center space-x-1 sm:space-x-4">
              <button
                onClick={() => setViewMode(ViewMode.DASHBOARD)}
                className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                  viewMode === ViewMode.DASHBOARD 
                    ? 'bg-blue-50 text-blue-700' 
                    : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'
                }`}
              >
                Dashboard
              </button>
              <button
                onClick={() => setViewMode(ViewMode.HISTORY)}
                className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                  viewMode === ViewMode.HISTORY 
                    ? 'bg-blue-50 text-blue-700' 
                    : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'
                }`}
              >
                Change Log
              </button>
              <button
                onClick={() => setViewMode(ViewMode.IMPORT)}
                className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                  viewMode === ViewMode.IMPORT 
                    ? 'bg-blue-50 text-blue-700' 
                    : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'
                }`}
              >
                Update Data
              </button>
            </nav>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {viewMode === ViewMode.DASHBOARD && (
          <div className="space-y-6">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 bg-slate-900 text-white p-6 rounded-2xl shadow-lg">
              <div>
                <h2 className="text-2xl font-bold">Portfolio Overview</h2>
                <p className="text-slate-400 mt-1">
                  Tracking User: <span className="text-white font-mono font-semibold">sth_</span>
                </p>
                <div className="mt-4 flex items-center space-x-6">
                  <div>
                    <span className="text-xs uppercase text-slate-500 font-bold tracking-wider">Total Positions</span>
                    <p className="text-3xl font-bold mt-1">{currentStocks.length}</p>
                  </div>
                  <div>
                    <span className="text-xs uppercase text-slate-500 font-bold tracking-wider">Last Update</span>
